import React from 'react';
import NavBar from './NavBar';


const Mainpage = () => {
  return (
    <>
      <NavBar/>
        <div class="p-2 p-md-3 mb-4 rounded text-body-emphasis bg-body-secondary">
            <div class="col-lg-6 px-0">
                <h1 class="display-4 fst-italic">Madan Kumar Paudel</h1>
                <p class="lead my-3">Dedicated IT Manager with over seven years of experience in the hospitality sector, adept at leveraging technology to enhance guest experiences and optimize operational efficiency.
                <br/>
                Part-time Python and React developer passionate about crafting innovative solutions.</p>                
            </div>
        </div>
    </>
  )
}

export default Mainpage
